  ('disabled-0a2fc18c-moex-00024', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-decd973b', 'sub-disabled-0a2fc18c-02', NULL, 'single_choice', '關於有限公司董事之敘述，下列何者正確？', '["董事得經股東表決權過半數之同意，就有行為能力之股東中選任之", "不得無故辭職", "董事至少3人且不用組成董事會", "有限公司章程應記載董事姓名或名稱"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00025', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-decd973b', 'sub-disabled-0a2fc18c-02', NULL, 'single_choice', '下列何者非家庭暴力防治法之保護對象？', '["遭受前夫精神騷擾及脅迫者", "目睹父親毆打母親之小孩", "同住之伯父恐嚇將斷其手腳", "要求交往但遭拒絕之男同學，恐嚇將殺害其全家"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00026', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-decd973b', 'sub-disabled-0a2fc18c-02', NULL, 'single_choice', '下列何種契約是民法債編所規定之有名契約？', '["代理契約", "醫療契約", "授權契約", "出版契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00027', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-decd973b', 'sub-disabled-0a2fc18c-02', NULL, 'single_choice', '有關國民參與審判制度之進行，下列敘述何者錯誤？', '["檢察官起訴時，應向管轄法院提出起訴書，並不得將卷宗及證物一併送 交法院", "起訴書不得記載使法院就案件產生預斷之虞之內容", "起訴書就犯罪事實之記載，以載明日、時、處所及方法特定之", "法院於第一次審判期日前，認為檢察官指出之證明方法顯不足認定被告 有成立犯罪之可能時，應以裁定定期通知檢察官補正"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00028', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-decd973b', 'sub-disabled-0a2fc18c-02', NULL, 'single_choice', '甲出賣其所有之 A 地於乙，甲交付 A 地於乙，乙為 A 地所有人。下列敘 述，何者錯誤？', '["若乙脅迫甲締結A地買賣契約，甲得撤銷買賣契約", "若無約定，甲尚未移轉A地所有權於乙，乙得拒絕支付價金於甲", "若乙出賣A地於丙者，乙與丙間之A地買賣契約，效力未定", "若乙移轉A地所有權並辦理移轉登記於善意之丁，丁為A地所有人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00029', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-decd973b', 'sub-disabled-0a2fc18c-02', NULL, 'single_choice', '甲為 22 歲之美國籍人士，來臺灣受僱於某僱用勞工 5 人以上之公司，擔 任兼職工作，依我國勞工保險條例之規定，下列敘述何者正確？', '["甲為外國籍員工，不得參加我國之勞工保險", "應由雇主為甲申報參加勞工保險", "甲為兼職員工，雇主無須為甲辦理投保", "甲無投保義務，仍得自願參加勞工保險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00030', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-decd973b', 'sub-disabled-0a2fc18c-02', NULL, 'single_choice', '下列有關責任的敘述，何者錯誤？', '["責任的成立，以義務的違反為必要條件", "法律上的責任基本上是以客觀主義為原則，再輔以主觀主義的修正與擴充", "在現代複雜的工商經濟下，為謀損害風險之均衡負擔，漸漸偏向客觀主 義之責任類型", "對行為人要求其負法律上責任，而科以刑罰或賠償損害，在法學中之運 作原則為歸責原理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00031', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-decd973b', 'sub-disabled-0a2fc18c-02', NULL, 'single_choice', '關於法律之制定，下列敘述何者正確？', '["法律由立法院通過，總統公布，得稱為通則", "法律應經立法院通過，行政院院長覆議及公布", "應以法律規定之事項，於未規定前，均得以命令定之", "關於執行法律之細節性、技術性次要事項，僅得由行政機關發布命令為 規範，不得以法律定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00032', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-decd973b', 'sub-disabled-0a2fc18c-02', NULL, 'single_choice', '依司法院大法官解釋及憲法訴訟法規定，關於法官聲請法規範憲法審查之 敘述，下列何者錯誤？', '["依法公布施行之法律，法官應以其為審判之依據，不得認定法律為違憲 而逕行拒絕適用", "憲法之效力既高於法律，法官有優先遵守之義務", "各法院就其審理之案件，對裁判上所應適用之行政命令，認有違憲疑慮 時，應聲請憲法法庭審查", "法官聲請法規範憲法審查，應於聲請書敘明客觀上形成確信法規範違憲 之法律見解"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00033', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-decd973b', 'sub-disabled-0a2fc18c-02', NULL, 'single_choice', '甲向乙購買1本A書，價金新臺幣（以下同）1000元。甲以1張1000元 鈔票付書款後，乙將A書交給甲，甲帶著A書離去。下列敘述，何者正確？', '["A書的買賣契約屬於處分行為", "甲給乙1000元的行為屬於負擔行為", "甲、乙間成立了3個契約", "甲、乙間僅作成了1個物權行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL)
